// =============================================
// Um Pato e um Sonho - main.js
// v0.0.2 - Fix WebView Android sprites
// Substituido THREE.Sprite por THREE.Mesh
// Texturas pre-carregadas via Image() nativo
// =============================================

const IMGS = {
  idle1:    "data:image/png;base64,",
  idle2:    "data:image/png;base64,",
  walk1:    "data:image/png;base64,",
  walk2:    "data:image/png;base64,",
  arvore:   "data:image/png;base64,",
  rocha:    "data:image/png;base64,",
  rabbit:   "data:image/png;base64,",
  icongame: "data:image/png;base64,",
  healthbar:"data:image/png;base64,",
};

// ---- CONSTANTES ----
const WORLD_W     = 2400;
const WORLD_H     = 2400;
const PLAYER_SPEED = 180;
const ANIM_INTERVAL = 120;

// ---- WEBGL CHECK ----
function checkWebGL() {
  try {
    const c = document.createElement('canvas');
    return !!(c.getContext('webgl') || c.getContext('experimental-webgl'));
  } catch(e) { return false; }
}

if (!checkWebGL()) {
  document.body.innerHTML = '<div style="color:#fff;font-family:monospace;padding:40px;background:#1a1a1a;height:100vh;display:flex;align-items:center;justify-content:center;text-align:center;font-size:14px;">WebGL nao disponivel neste dispositivo.<br>Tente em outro navegador.</div>';
  throw new Error('WebGL indisponivel');
}

// ---- RENDERER ----
const renderer = new THREE.WebGLRenderer({
  antialias: false,
  powerPreference: 'high-performance',
  alpha: false,
});
renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
renderer.setSize(window.innerWidth, window.innerHeight);
renderer.setClearColor(0x5a8f3c);
renderer.sortObjects = true;
document.getElementById('game-canvas').appendChild(renderer.domElement);

// ---- CAMERA ----
const VIEW_H = 400;
let VIEW_W = VIEW_H * (window.innerWidth / window.innerHeight);
const camera = new THREE.OrthographicCamera(
  -VIEW_W/2, VIEW_W/2, VIEW_H/2, -VIEW_H/2, 0.1, 2000
);
camera.position.set(0, 0, 100);
camera.lookAt(0, 0, 0);

const scene = new THREE.Scene();

// ---- PRE-CARREGAMENTO DE TEXTURAS via Image() nativo ----
// Garante compatibilidade com WebView Android
function loadTexNative(src) {
  return new Promise((resolve) => {
    const img = new Image();
    img.onload = () => {
      const tex = new THREE.Texture(img);
      tex.magFilter = THREE.NearestFilter;
      tex.minFilter  = THREE.NearestFilter;
      tex.needsUpdate = true;
      resolve(tex);
    };
    img.onerror = () => {
      // fallback: canvas magenta 8x8
      const canvas = document.createElement('canvas');
      canvas.width = canvas.height = 8;
      const ctx = canvas.getContext('2d');
      ctx.fillStyle = '#ff00ff';
      ctx.fillRect(0, 0, 8, 8);
      const tex = new THREE.CanvasTexture(canvas);
      tex.magFilter = THREE.NearestFilter;
      tex.minFilter  = THREE.NearestFilter;
      resolve(tex);
    };
    img.src = src;
  });
}

// ---- MESH FACTORY (substitui THREE.Sprite) ----
// PlaneGeometry + MeshBasicMaterial = mais estavel no WebView
function makeMesh(tex, w, h, z) {
  const geom = new THREE.PlaneGeometry(w, h);
  const mat  = new THREE.MeshBasicMaterial({
    map: tex,
    transparent: true,
    alphaTest: 0.05,
    depthWrite: false,
    side: THREE.DoubleSide,
  });
  const mesh = new THREE.Mesh(geom, mat);
  mesh.position.z = z || 0;
  return mesh;
}

// ---- GROUND ----
function makeGround() {
  const canvas = document.createElement('canvas');
  canvas.width = canvas.height = 256;
  const ctx = canvas.getContext('2d');
  const grassColors = ['#4e7f34','#5a8f3c','#62973f','#4a7830','#5c9140'];
  ctx.fillStyle = '#5a8f3c';
  ctx.fillRect(0, 0, 256, 256);
  for (let i = 0; i < 600; i++) {
    ctx.fillStyle = grassColors[Math.floor(Math.random() * grassColors.length)];
    const x = Math.floor(Math.random() * 64) * 4;
    const y = Math.floor(Math.random() * 64) * 4;
    ctx.fillRect(x, y, 4, 4);
  }
  const groundTex = new THREE.CanvasTexture(canvas);
  groundTex.wrapS = groundTex.wrapT = THREE.RepeatWrapping;
  groundTex.repeat.set(WORLD_W / 128, WORLD_H / 128);
  groundTex.magFilter = THREE.NearestFilter;
  groundTex.minFilter  = THREE.NearestFilter;

  const mesh = new THREE.Mesh(
    new THREE.PlaneGeometry(WORLD_W, WORLD_H),
    new THREE.MeshBasicMaterial({ map: groundTex })
  );
  mesh.position.z = 0;
  mesh.renderOrder = 0;
  scene.add(mesh);
}

// ---- HEALTHBAR HUD (canvas 2D sobreposto) ----
const hudCanvas = document.getElementById('hud-canvas');
const hudCtx    = hudCanvas.getContext('2d');
let healthbarImg = null;
const MAX_HP = 100;
let playerHP = MAX_HP;

function resizeHud() {
  hudCanvas.width  = window.innerWidth;
  hudCanvas.height = window.innerHeight;
}
resizeHud();

function drawHUD() {
  hudCtx.clearRect(0, 0, hudCanvas.width, hudCanvas.height);
  if (!healthbarImg) return;

  // A spritesheet de healthbar tem 6 frames empilhados verticalmente
  // Cada frame representa um estado de vida
  const frames = 6;
  const frameH = healthbarImg.naturalHeight / frames;
  const frameW = healthbarImg.naturalWidth;

  // Escolhe frame baseado no HP (0=cheio, 5=vazio)
  const frameIdx = Math.min(frames - 1, Math.floor((1 - playerHP / MAX_HP) * frames));

  const drawW = Math.min(240, window.innerWidth * 0.55);
  const drawH = drawW * (frameH / frameW);
  const x = 16;
  const y = window.innerHeight - drawH - 20;

  hudCtx.imageSmoothingEnabled = false;
  hudCtx.drawImage(
    healthbarImg,
    0, frameIdx * frameH, frameW, frameH,
    x, y, drawW, drawH
  );
}

// ---- INICIALIZAR JOGO (apos assets carregarem) ----
async function initGame() {
  // Carrega todas as texturas nativamente
  const textures = {
    idle1:  await loadTexNative(IMGS.idle1),
    idle2:  await loadTexNative(IMGS.idle2),
    walk1:  await loadTexNative(IMGS.walk1),
    walk2:  await loadTexNative(IMGS.walk2),
    arvore: await loadTexNative(IMGS.arvore),
    rocha:  await loadTexNative(IMGS.rocha),
    rabbit: await loadTexNative(IMGS.rabbit),
  };

  // Carrega healthbar para o HUD canvas
  healthbarImg = new Image();
  await new Promise(res => {
    healthbarImg.onload = res;
    healthbarImg.onerror = res;
    healthbarImg.src = IMGS.healthbar;
  });

  makeGround();

  // ---- PLAYER ----
  const player = {
    mesh: makeMesh(textures.idle1, 48, 48, 2),
    x: 0, y: 0,
    animTimer: 0,
    animFrame: 0,
    isMoving: false,
    facingLeft: false,
    w: 28, h: 28,
  };
  scene.add(player.mesh);

  // ---- OBSTACULOS ----
  const obstacles = [];

  function spawnObstacle(type, x, y) {
    const isTree = type === 'arvore';
    const w = isTree ? 90 : 72;
    const h = isTree ? 90 : 60;
    const mesh = makeMesh(textures[type], w, h, 1);
    mesh.position.set(x, y, 1);
    scene.add(mesh);
    obstacles.push({ mesh, x, y, w: isTree ? 28 : 36, h: isTree ? 20 : 28 });
  }

  const objectDefs = [
    { type:'arvore', x:-300, y: 200 }, { type:'arvore', x: 250, y: 300 },
    { type:'arvore', x:-150, y:-350 }, { type:'arvore', x: 400, y:-200 },
    { type:'arvore', x:-450, y: 100 }, { type:'arvore', x: 100, y:-450 },
    { type:'arvore', x:-200, y: 450 }, { type:'arvore', x: 500, y: 150 },
    { type:'arvore', x:-500, y:-250 }, { type:'arvore', x: 350, y: 450 },
    { type:'arvore', x:-350, y:-500 }, { type:'arvore', x: 600, y:-400 },
    { type:'arvore', x:-600, y: 350 },
    { type:'rocha',  x: 180, y:-180 }, { type:'rocha',  x:-200, y: 120 },
    { type:'rocha',  x: 350, y: -50 }, { type:'rocha',  x:-400, y:-150 },
    { type:'rocha',  x:  50, y: 320 }, { type:'rocha',  x:-120, y:-280 },
    { type:'rocha',  x: 450, y: 300 }, { type:'rocha',  x:-350, y: 400 },
  ];
  objectDefs.forEach(o => spawnObstacle(o.type, o.x, o.y));

  // ---- COELHOS ----
  const rabbits = [];
  function spawnRabbit(x, y) {
    const mesh = makeMesh(textures.rabbit, 36, 36, 1);
    mesh.position.set(x, y, 1);
    scene.add(mesh);
    rabbits.push({ mesh, x, y, w: 20, h: 20 });
  }
  [{x:120,y:220},{x:-180,y:-100},{x:320,y:-320}].forEach(r => spawnRabbit(r.x,r.y));

  // ---- INPUT ----
  const keys = {};
  window.addEventListener('keydown', e => { keys[e.code] = true; });
  window.addEventListener('keyup',   e => { keys[e.code] = false; });

  let joystick = { active:false, startX:0, startY:0, dx:0, dy:0 };
  const joyElem = document.getElementById('joystick');
  const joyKnob = document.getElementById('joystick-knob');

  joyElem.addEventListener('touchstart', e => {
    e.preventDefault();
    const t = e.touches[0];
    joystick = { active:true, startX:t.clientX, startY:t.clientY, dx:0, dy:0 };
  }, {passive:false});

  window.addEventListener('touchmove', e => {
    if (!joystick.active) return;
    e.preventDefault();
    const t = e.touches[0];
    const dx = t.clientX - joystick.startX;
    const dy = t.clientY - joystick.startY;
    const dist = Math.sqrt(dx*dx + dy*dy);
    const max  = 50;
    const clamped = Math.min(dist, max);
    const angle = Math.atan2(dy, dx);
    joystick.dx = Math.cos(angle) * clamped / max;
    joystick.dy = Math.sin(angle) * clamped / max;
    joyKnob.style.transform = `translate(${Math.cos(angle)*clamped}px,${Math.sin(angle)*clamped}px)`;
  }, {passive:false});

  window.addEventListener('touchend', () => {
    joystick = { active:false, startX:0, startY:0, dx:0, dy:0 };
    joyKnob.style.transform = 'translate(0,0)';
  });

  // ---- COLISAO AABB ----
  function checkAABB(ax,ay,aw,ah,bx,by,bw,bh) {
    return Math.abs(ax-bx) < (aw+bw)/2 && Math.abs(ay-by) < (ah+bh)/2;
  }

  // ---- GAME LOOP ----
  let lastTime = performance.now();

  function update(dt) {
    let moveX = 0, moveY = 0;
    if (keys['ArrowLeft']  || keys['KeyA']) moveX -= 1;
    if (keys['ArrowRight'] || keys['KeyD']) moveX += 1;
    if (keys['ArrowUp']    || keys['KeyW']) moveY += 1;
    if (keys['ArrowDown']  || keys['KeyS']) moveY -= 1;
    if (joystick.active) { moveX += joystick.dx; moveY -= joystick.dy; }

    const len = Math.sqrt(moveX*moveX + moveY*moveY);
    if (len > 1) { moveX /= len; moveY /= len; }

    player.isMoving = len > 0.05;
    if (moveX < -0.05) player.facingLeft = true;
    if (moveX >  0.05) player.facingLeft = false;

    const halfW = WORLD_W/2 - 40, halfH = WORLD_H/2 - 40;
    let nx = Math.max(-halfW, Math.min(halfW, player.x + moveX * PLAYER_SPEED * dt));
    let ny = Math.max(-halfH, Math.min(halfH, player.y + moveY * PLAYER_SPEED * dt));

    const all = [...obstacles, ...rabbits];
    let colX = false, colY = false;
    for (const o of all) if (checkAABB(nx, player.y, player.w, player.h, o.x, o.y, o.w, o.h)) { colX = true; break; }
    if (!colX) player.x = nx;
    for (const o of all) if (checkAABB(player.x, ny, player.w, player.h, o.x, o.y, o.w, o.h)) { colY = true; break; }
    if (!colY) player.y = ny;

    // Animacao
    player.animTimer += dt * 1000;
    if (player.animTimer >= ANIM_INTERVAL) {
      player.animTimer = 0;
      player.animFrame = 1 - player.animFrame;
    }
    const animKey = player.isMoving
      ? (player.animFrame === 0 ? 'walk1' : 'walk2')
      : (player.animFrame === 0 ? 'idle1' : 'idle2');
    player.mesh.material.map = textures[animKey];
    player.mesh.material.needsUpdate = true;

    // Flip horizontal
    player.mesh.scale.x = player.facingLeft ? -1 : 1;

    // Posicao
    player.mesh.position.set(player.x, player.y, 2);

    // Depth sort por Y — z mais alto = frente
    const allMeshes = [
      ...obstacles.map(o => ({mesh: o.mesh, y: o.y})),
      ...rabbits.map(r   => ({mesh: r.mesh, y: r.y})),
      {mesh: player.mesh, y: player.y},
    ];
    allMeshes.forEach(obj => {
      obj.mesh.position.z = 1 + (500 - obj.y) * 0.001;
    });

    // Camera segue o jogador com limites
    const hVW = VIEW_W/2, hVH = VIEW_H/2;
    camera.position.set(
      Math.max(-WORLD_W/2+hVW, Math.min(WORLD_W/2-hVW, player.x)),
      Math.max(-WORLD_H/2+hVH, Math.min(WORLD_H/2-hVH, player.y)),
      100
    );
  }

  function loop(now) {
    const dt = Math.min((now - lastTime) / 1000, 0.05);
    lastTime = now;
    update(dt);
    renderer.render(scene, camera);
    drawHUD();
    requestAnimationFrame(loop);
  }

  requestAnimationFrame(loop);
}

// ---- RESIZE ----
window.addEventListener('resize', () => {
  const w = window.innerWidth, h = window.innerHeight;
  renderer.setSize(w, h);
  VIEW_W = VIEW_H * (w / h);
  camera.left   = -VIEW_W/2;
  camera.right  =  VIEW_W/2;
  camera.top    =  VIEW_H/2;
  camera.bottom = -VIEW_H/2;
  camera.updateProjectionMatrix();
  resizeHud();
});

// Inicia quando o DOM estiver pronto
initGame().catch(err => console.error('Erro ao iniciar jogo:', err));
